// DO NOT EDIT imports — all available components are pre-imported.
// prettier-ignore-start
import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
// import { ... } from '@ggui-ai/adapters'; // TODO: adapter integration
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  city: string; // City name
  temperature: number; // Current temperature
  condition: string; // Weather condition (Sunny, Cloudy, Rainy, etc.)
  humidity: number; // Humidity percentage
  windSpeed: number; // Wind speed
  unit: string; // Temperature unit (C or F)
  forecast: Array<{ day?: string; icon?: string; high?: number; low?: number }>; // 5-day forecast array
}
// DO NOT EDIT types below — auto-generated from the data contract





// ViewProps: define the props that ComponentView needs to render the UI.
// Include all data, callbacks, and computed values that the View will use.
interface ViewProps {
  city: string;
  temperature: number;
  condition: string;
  humidity: number;
  windSpeed: number;
  unit: string; // Default to 'C' if not provided
  forecast: Array<{ day?: string; icon?: string; high?: number; low?: number }>;
  weatherEmoji: string;
}

// Controller: business logic, wire hooks, data transformations
function ComponentController(props: Props): ViewProps {
  const getWeatherEmoji = (condition: string): string => {
    const lowerCondition = condition.toLowerCase();
    if (lowerCondition.includes('sunny') || lowerCondition.includes('clear')) return '☀️';
    if (lowerCondition.includes('cloudy') || lowerCondition.includes('overcast')) return '☁️';
    if (lowerCondition.includes('rainy') || lowerCondition.includes('rain')) return '🌧️';
    if (lowerCondition.includes('snowy') || lowerCondition.includes('snow')) return '❄️';
    if (lowerCondition.includes('thunder') || lowerCondition.includes('storm')) return '⛈️';
    if (lowerCondition.includes('foggy') || lowerCondition.includes('fog')) return '🌫️';
    return '🌤️';
  };

  const weatherEmoji = getWeatherEmoji(props.condition);
  const resolvedUnit = props.unit || 'C';

  return {
    city: props.city,
    temperature: props.temperature,
    condition: props.condition,
    humidity: props.humidity,
    windSpeed: props.windSpeed,
    unit: resolvedUnit,
    forecast: props.forecast,
    weatherEmoji,
  };
}
}

// View: presentation and UI interactions (can have its own UI state like tabs, modals, hover)
function ComponentView(props: ViewProps) {
  return (
    <Container maxWidth="lg" padding={24}>
      <Stack gap={24}>
        {/* CURRENT WEATHER CARD */}
        <Card shadow="md" padding={32} radius="lg">
          <Stack gap={16}>
            {/* City and Condition Header */}
            <Stack gap={8}>
              <Heading level={2}>{props.city}</Heading>
              <Stack direction="horizontal" gap={12} align="center">
                <Icon name={props.weatherEmoji} size={48} />
                <Text variant="bodyLarge" color="var(--ggui-color-onSurfaceVariant, #52525b)">{props.condition}</Text>
              </Stack>
            </Stack>

            {/* Temperature - Large and Prominent */}
            <Box background="var(--ggui-color-primary-50, #f0f9ff)" padding={24} borderRadius="var(--ggui-shape-radius-lg, 12px)">
              <Stack gap={8} align="center">
                <Heading level={1} align="center" style={{ fontSize: 'var(--ggui-font-size-4xl, 36px)', fontWeight: 'var(--ggui-font-weight-bold, 700)' }}>
                  {props.temperature}°{props.unit}
                </Heading>
              </Stack>
            </Box>

            {/* Weather Details Grid */}
            <Stack direction="horizontal" gap={16} align="stretch">
              <Card shadow="sm" padding={16} radius="md" style={{ flex: 1 }}>
                <Stack gap={8} align="center">
                  <Icon name="droplets" size={24} color="var(--ggui-color-primary-600, #0284c7)" />
                  <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">Humidity</Text>
                  <Text variant="label" color="var(--ggui-color-onSurface, #18181b)">{props.humidity}%</Text>
                </Stack>
              </Card>
              <Card shadow="sm" padding={16} radius="md" style={{ flex: 1 }}>
                <Stack gap={8} align="center">
                  <Icon name="wind" size={24} color="var(--ggui-color-primary-600, #0284c7)" />
                  <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">Wind Speed</Text>
                  <Text variant="label" color="var(--ggui-color-onSurface, #18181b)">{props.windSpeed} m/s</Text>
                </Stack>
              </Card>
            </Stack>
          </Stack>
        </Card>

        {/* 5-DAY FORECAST STRIP */}
        <Stack gap={12}>
          <Heading level={3}>5-Day Forecast</Heading>
          <Stack direction="horizontal" gap={12} align="stretch" wrap>
            {props.forecast && props.forecast.length > 0 ? (
              props.forecast.map((day, index) => (
                <Card key={index} shadow="sm" padding={12} radius="md" style={{ flex: '0 1 auto', minWidth: '80px', textAlign: 'center' }}>
                  <Stack gap={8} align="center">
                    {day.day && <Text variant="label" color="var(--ggui-color-onSurface, #18181b)">{day.day}</Text>}
                    {day.icon && <Icon name={day.icon} size={32} />}
                    {(day.high || day.low) && (
                      <Stack gap={4} align="center">
                         {day.high !== undefined && <Text variant="caption" color="var(--ggui-color-onSurface, #18181b)" weight="medium">H: {day.high}°{props.unit}</Text>}
                         {day.low !== undefined && <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">L: {day.low}°{props.unit}</Text>}
                      </Stack>
                    )}
                  </Stack>
                </Card>
              ))
            ) : (
              <Text variant="body" color="var(--ggui-color-onSurfaceVariant, #52525b)">No forecast data available</Text>
            )}
          </Stack>
        </Stack>
      </Stack>
    </Container>
  );
}

// DO NOT EDIT render — it connects Controller to View
export default function render(props: Props) {
  const viewProps = ComponentController(props);
  return <ComponentView {...viewProps} />;
}
